import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int numNodes = (int) n;
        List<List<long[]>> adj = new ArrayList<>();
        List<List<long[]>> reverseAdj = new ArrayList<>();
        for (int i = 0; i < numNodes; i++) {
            adj.add(new ArrayList<>());
            reverseAdj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];
            adj.get(u).add(new long[]{v, w});
            reverseAdj.get(v).add(new long[]{u, w});
        }

        long[][] dist = new long[numNodes][2];
        for (int i = 0; i < numNodes; i++) {
            dist[i][0] = Long.MAX_VALUE;
            dist[i][1] = Long.MAX_VALUE;
        }
        dist[0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[2]));
        pq.offer(new long[]{0, 0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int node = (int) current[0];
            int used = (int) current[1];
            long cost = current[2];

            if (node == numNodes - 1) {
                return cost;
            }
            if (cost > dist[node][used]) {
                continue;
            }

            for (long[] edge : adj.get(node)) {
                int v = (int) edge[0];
                long w = edge[1];
                long newCost = cost + w;
                if (newCost < dist[v][used]) {
                    dist[v][used] = newCost;
                    pq.offer(new long[]{v, used, newCost});
                }
            }

            if (used == 0) {
                for (long[] edge : reverseAdj.get(node)) {
                    int u = (int) edge[0];
                    long w = edge[1];
                    long newCost = cost + 2 * w;
                    if (newCost < dist[u][1]) {
                        dist[u][1] = newCost;
                        pq.offer(new long[]{u, 1, newCost});
                    }
                }
            }
        }

        long res = Math.min(dist[numNodes - 1][0], dist[numNodes - 1][1]);
        return res == Long.MAX_VALUE ? -1 : res;
    }
}
